diff --git a/examples/handlebars/components/collated/collated.spec.js b/examples/handlebars/components/collated/collated.spec.js
new file mode 100644
index 0000000..0396eda
--- /dev/null
+++ b/examples/handlebars/components/collated/collated.spec.js
@@ -0,0 +1,12 @@
+const fractal = require('../../fractal.config.js');
+
+describe('tree', () => {
+    beforeEach(async () => {
+        await fractal.load();
+    });
+
+    it('renders collated components collated', async () => {
+        const render = await fractal.components.find('@collated').render(null, null, { collate: true });
+        expect(render).toMatchSnapshot();
+    });
+});

